324→/**
325→ * Verifies that a leaf containing a newline exist in the closed range [from] - [to]. Also, returns true in case any of
326→ * the boundary nodes [from] or [to] contains a newline.
327→ */
328→public fun hasNewLineInClosedRange(
329→    from: ASTNode,
330→    to: ASTNode,
331→): Boolean =
332→    from.isWhiteSpaceWithNewline() ||
333→        leavesInOpenRange(from, to).any { it.textContains('\n') } ||
334→        to.isWhiteSpaceWithNewline()
