            .let { whiteSpaceAfterColon ->
                if (whiteSpaceAfterColon?.text != " ") {
                    // In case the whitespace contains a newline, check if putting everything on one line
                    // would exceed the max line length. If so, leave it as is to avoid violating max-line-length rule.
                    if (whiteSpaceAfterColon != null &&
                        whiteSpaceAfterColon.textContains('\n') &&
                        maxLineLength != MAX_LINE_LENGTH_PROPERTY_OFF
                    ) {
                        val lineLengthIfSingleLine = calculateLineLengthIfSingleLine(node, whiteSpaceAfterColon)
                        if (lineLengthIfSingleLine > maxLineLength) {
                            return
                        }
