    private fun calculateLineLengthIfSingleLine(colonNode: ASTNode, whiteSpaceAfterColon: ASTNode): Int {
        // Calculate the line length if we were to put the return type on the same line as the function signature.
        // Line length = position after colon + 1 (for space) + length of text from return type to next newline
        val lengthBeforeColon = colonNode.column - 1
        val colonLength = colonNode.textLength
        val spaceLength = 1

        // Calculate length of text after whitespace until the next newline
        var textAfterLength = 0
        var leaf = whiteSpaceAfterColon.nextLeaf()
        while (leaf != null) {
            if (leaf.elementType == WHITE_SPACE && leaf.textContains('\n')) {
                break
            }
            textAfterLength += leaf.textLength
            leaf = leaf.nextLeaf()
        }

        return lengthBeforeColon + colonLength + spaceLength + textAfterLength
    }
