        val lengthBeforeColon = colonNode.column - 1
        val colonLength = colonNode.textLength
        val spaceLength = 1

        // Calculate length of text after whitespace until the next newline
        var textAfterLength = 0
        var leaf = whiteSpaceAfterColon.nextLeaf()
        while (leaf != null) {
            if (leaf.elementType == WHITE_SPACE && leaf.textContains('\n')) {
